Future<String> getUserName() async {
  await Future.delayed(Duration(seconds: 1));
  return 'Alice';
}

Future<int> getUserAge() async {
  await Future.delayed(Duration(seconds: 1));
  return 30;
}

void main() async {
  print('Loading user data...');

  var name = await getUserName();
  var age = await getUserAge();

  print('User: $name, Age: $age');
  print('Done');
}
